export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "00:50。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "灣岸中央急救醫療中心。急診等候區。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪坐在第三排塑膠椅上。不是因為想坐。是因為她走不出去。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個小時前她被帶進這裡。站務安全人員和警方的先遣人員先後問過她同一件事——施工通道裡她看到了什麼。她說了。他們說還要補。現場負責人還沒到。所以她等。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯流程。又是流程。不是不讓我走。是「還沒輪到讓我走」。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "等候區的冷氣太強。她把外套拉鏈拉到最上面。口袋裡那張紙還在。小鏡子的布套還在。手機螢幕暗著。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一名警員從走廊那頭走過來。制服。沒有名字牌。腳步很慢，像在巡。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "先不要離開。等現場負責人過來，還要補妳在通道裡看到的內容。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯好。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "警員沒有多說。走了。塑膠椅的另一端有人咳了一聲。牆上的時鐘走得很慢。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站起來。走向急診櫃台。玻璃窗後面坐著一個穿制服的人。頭沒有抬起來。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.HospitalClerk, character: "醫院櫃台", dialogue: "請問要辦什麼？", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯我想確認一下，剛才被送進來的傷者——施工通道那件——", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.HospitalClerk, character: "醫院櫃台", dialogue: "患者相關資訊只能提供給家屬或警方。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "語氣很平。沒有為難。沒有懷疑。只是照規定。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯我不是家屬。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.HospitalClerk, character: "醫院櫃台", dialogue: "那很抱歉，這邊無法提供。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "玻璃窗後的人低下頭，繼續寫東西。對話結束了。像一道門關上。沒有鎖，但推不開。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不是家屬。不是警方。是目擊者。目擊者可以留在醫院裡等，但不能知道傷者怎麼了。流程把我放在這裡，又把我擋在這裡。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走回等候區。坐下。第三排。同一個位置。椅子的塑膠邊緣硌著大腿。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊另一側的門開了。兩個穿綠色刷手衣的人走出來。聲音不大，但走廊安靜，字字清楚。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.MedicalStaff, character: "醫護", dialogue: "暫時穩定。血壓拉回來了。先送觀察區，再排影像。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.MedicalStaff, character: "醫護", dialogue: "還要觀察。家屬聯絡上了嗎？", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.MedicalStaff, character: "醫護", dialogue: "還在確認。先這樣。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門又關了。聲音被隔在裡面。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯暫時穩定。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯血壓拉回來了。還要觀察。他還活著。不是「快死了」。是「暫時穩定」。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她盯著自己的膝蓋。手指在膝蓋上收緊。又鬆開。收緊。鬆開。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯也許。也許這一輪真的不一樣。他沒有死在第七車。他沒有死在施工通道。他進了醫院。血壓拉回來了。暫時穩定。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她從內袋摸出那張紙。攤開。已經寫了很多行。指甲壓出的摺痕。沒有筆。她用指甲再壓。在空白處畫出兩條直線。一條豎線隔開。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一輪。第二輪。寫在一起。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她壓。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一輪：千田死在第七車。第二輪：千田活著進醫院。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一輪：外殼在我手上，被收走，我變成嫌疑人。第二輪：外殼疑似在病人物袋裡。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一輪：我是持尖銳物者。第二輪：我是重要目擊者。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一輪：死亡被車廂畫面定義。第二輪：死亡可能被醫院流程定義。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那四行。兩欄。像一份查核報告的初稿。左邊是已經發生過的。右邊是正在發生的。右邊的每一行都比左邊好。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯每一行都更好。千田活著。我不是嫌疑人。外殼沒有被當成凶器。這本該是——", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有寫下「勝利」兩個字。手指停在紙上。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不對。不是勝利。是「暫時穩定」。醫院裡沒有「勝利」這個詞。只有「觀察」。只有「等」。只有「還沒有急變」。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把紙摺起來。塞回內袋。手指碰到小鏡子的布套。涼的。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊另一側傳來輪子聲。很輕。橡膠輪碾過塑膠地板的聲音。她抬頭。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一名保安推著保管推車從走廊那頭走過。推車上放著幾個不透明的收納箱。其中一個箱子的側面貼著標籤。她看不清標籤上的字。但箱子的尺寸、推車的方向——", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯保安室的方向。病人物袋。還在那裡。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯千田暫時穩定。但袋子不在他身邊。袋子在保安室。在流程裡。在「安全暫存」裡。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "推車消失在走廊轉角。輪子聲越來越遠。然後聽不見了。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯先查外殼。不是因為外殼比千田重要。是因為千田就算醒來，也可能很快被流程隔離。家屬還沒聯絡上。警方還沒來。觀察區的門一關，我就什麼都碰不到了。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯外殼也是。袋子在保安室暫存。暫存的意思是——它還沒有被定義。還沒有被分類。還沒有被改名。等它被改了名，我就認不出它了。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯趁它還沒有變成別的東西。去。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站起來。椅子的塑膠邊緣離開大腿，留下一道涼的印子。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走向走廊。背後是等候區。等候區的燈很亮。走廊的燈更暗。暗的地方是保安室的方向。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯活著的人還會被帶走。活著的證詞也會被封起來。簾子可以拉上。門可以關上。流程可以擋住。千田還在呼吸——但呼吸本身不是證據。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走進走廊。燈光從身後照過來，把她的影子拉得很長。影子落在塑膠地板上。很細。很孤獨。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "前方是保安室的方向。", background: Background.Chapter_8_Ch8_Act1_S0 },
];
